22	const COMPONENT_PREMIUM = 25;
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	const MAIN_ITEM_PREMIUM: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	const CURSE_SURCHARGE_RATE = 0.5;
35	const PROCESSING_FEE = 5;
36	const ROUNDING_PRECISION = 6;
37	
38	const componentBasePremium = (count: number): number => {
39	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
40	  return count * COMPONENT_PREMIUM;
41	};
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	
45	const countByType = (items: Item[]): Map<string, number> => {
46	  const counts = new Map<string, number>();
47	  for (const { type } of items) {
48	    if (COMPONENT_TYPES.includes(type)) {
49	      counts.set(type, (counts.get(type) ?? 0) + 1);
50	    }
51	  }
52	  return counts;
53	};
54	
55	const componentsBasePremium = (items: Item[]): number => {
56	  const counts = [...countByType(items).values()];
57	  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
58	};
59	
60	const mainItemsBasePremium = (items: Item[]): number =>
61	  items.reduce((total, item) => total + (MAIN_ITEM_PREMIUM[item.type] ?? 0), 0);
62	
63	const policyBasePremium = (items: Item[]): number =>
64	  mainItemsBasePremium(items) + componentsBasePremium(items);
65	
66	const itemBasePremium = (item: Item): number => MAIN_ITEM_PREMIUM[item.type] ?? 0;
67	
68	const itemSurcharges = (items: Item[]): number =>
69	  items.reduce(
70	    (total, item) =>
71	      total + (item.cursed ? CURSE_SURCHARGE_RATE * itemBasePremium(item) : 0),
72	    0,
73	  );
74	
75	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
76	  const results = scenario.steps.map((step) => {
77	    const base = policyBasePremium(step.items);
78	    const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
79	    const total = base + itemSurcharges(step.items) + firstInsurance + PROCESSING_FEE;
80	    const premium = Math.ceil(Number(total.toFixed(ROUNDING_PRECISION)));
81	    return { premium };
82	  });
83	  return { results };
84	};
